Here's a complete implementation:

### XAML

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="48,*" ColumnSpacing="12">
                    <VisualStateManager.VisualStateGroups>
                        <VisualStateGroup Name="CommonStates">
                            <VisualState Name="Normal">
                                <VisualState.Setters>
                                    <Setter Property="BackgroundColor" Value="Transparent" />
                                </VisualState.Setters>
                            </VisualState>
                            <VisualState Name="Selected">
                                <VisualState.Setters>
                                    <Setter Property="BackgroundColor"
                                            Value="{StaticResource Primary}" />
                                </VisualState.Setters>
                            </VisualState>
                        </VisualStateGroup>
                    </VisualStateManager.VisualStateGroups>
                    <Image Source="{Binding Icon}" WidthRequest="40" HeightRequest="40" />
                    <Label Grid.Column="1" Text="{Binding Name}" VerticalOptions="Center" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <ContentView>
                <Label Text="No items found."
                       HorizontalOptions="Center" VerticalOptions="Center" />
            </ContentView>
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

### ViewModel

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private ObservableCollection<Item> items = new();

    [ObservableProperty]
    private Item? currentItem;

    [ObservableProperty]
    private bool isRefreshing;

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [RelayCommand]
    private async Task Refresh()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            MainThread.BeginInvokeOnMainThread(() =>
            {
                Items.Clear();
                foreach (var item in data)
                    Items.Add(item);
            });
        }
        finally
        {
            IsRefreshing = false; // Must set to false to hide spinner
        }
    }

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (CurrentItem is null) return;
        await _nav.GoToAsync("DetailPage", new Dictionary<string, object>
        {
            { "Item", CurrentItem }
        });
        CurrentItem = null; // Reset so the same item can be re-selected
    }
}
```

### Key bindings explained

| XAML Property | ViewModel Property | Purpose |
|---|---|---|
| `RefreshView.IsRefreshing` | `IsRefreshing` (bool) | Shows/hides spinner; **must be set to `false`** when done |
| `RefreshView.Command` | `RefreshCommand` | Fires on pull-down; calls your API |
| `CollectionView.ItemsSource` | `Items` (ObservableCollection) | Use `ObservableCollection<T>` so add/remove auto-updates UI |
| `CollectionView.SelectedItem` | `CurrentItem` (TwoWay) | Tracks selected item; reset to `null` after navigation |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Triggers navigation to detail page |

### Important notes

- **Never use `ViewCell`** — the template root must be a `View` like `Grid`.
- **Always update collections on the UI thread** via `MainThread.BeginInvokeOnMainThread`.
- Reset `CurrentItem = null` after navigating so the user can tap the same item again.
- Set `x:DataType` on `DataTemplate` for compiled bindings and better performance.
